/** @typedef {{ uniform?: string, na?: boolean, segments?: object[], points?: object[] }} Chart */

const U = (v) => ({ uniform: v });
const NA = () => ({ na: true });
const S3 = (l, r, label = '0', kind = 'filled') => ({
  segments: [
    { pos: '25%', val: l, vert: l === '−' ? 'below' : 'above' },
    { pos: '75%', val: r },
  ],
  points: [{ pos: '50%', label, kind }],
});
const HOLE = (l, r) => S3(l, r, '0', 'open');
const DNE3 = (l, r) => ({
  segments: [
    { pos: '25%', val: l, vert: l === '−' ? 'below' : 'above' },
    { pos: '75%', val: r },
  ],
  points: [{ pos: '50%', label: '0', kind: 'open' }],
});

const holeGraph = (expr, point) => ({
  latex: expr,
  points: [{ id: 'hole', latex: point, pointStyle: 'OPEN', color: '#f87171' }],
});

const signGraph = () => ({
  expressions: [
    { id: 'pos', latex: 'y = 1 \\{x > 0\\}', color: '#b91c1c' },
    { id: 'neg', latex: 'y = -1 \\{x < 0\\}', color: '#b91c1c' },
  ],
  points: [
    { id: 'p1', latex: '(0, 1)', pointStyle: 'OPEN', color: '#f87171' },
    { id: 'p2', latex: '(0, -1)', pointStyle: 'OPEN', color: '#f87171' },
  ],
});

